213	    // loopback 信頼境界に乗るため bearer token は不要 (他 /v1/admin/* と同様)。
214	    const templateName = typeof body.template === "string" ? body.template.trim() : "";
215	    if (templateName) {
216	      const tpl = deps.delegation.findTemplateByCallName(templateName);
217	      if (!tpl) return c.json({ error: `unknown template: ${templateName}` }, 404);
218	      if (!tpl.is_active) return c.json({ error: `template inactive: ${templateName}` }, 400);
219	      const injectPrompt = body.inject_prompt === true;
220	      const tplArgs = isPlainObject(body.args) ? (body.args as Record<string, unknown>) : {};
221	      const cwdOverride = typeof body.cwd === "string" && body.cwd.trim() ? body.cwd.trim() : undefined;
222	
223	      if (injectPrompt) {
