309	  // 2. プラットフォーム別に process tree を kill (Win: taskkill /F /T, POSIX: SIGTERM)
310	  // 3. session を ended に遷移 + end event append (stopped_by: admin)
311	  // 4. session-end フロー (report 生成 / 独白を #報告 へ投稿 / persona release) を実行
312	  //    DELETE /v1/sessions/:id と同じ helper (control/end-session-flow.ts) を経由する.
313	  app.post("/v1/admin/stop-session/:id", async (c) => {
314	    const id = c.req.param("id");
315	    const session = deps.repo.findSession(id);
316	    if (!session) return c.json({ error: "not_found" }, 404);
317	    if (!session.metadata) {
