319	    }
320	    let meta: { lictor_pid?: number };
321	    try {
322	      meta = JSON.parse(session.metadata) as { lictor_pid?: number };
323	    } catch {
324	      return c.json({ error: "session.metadata is not JSON" }, 400);
325	    }
326	    if (typeof meta.lictor_pid !== "number") {
327	      return c.json({ error: "session.metadata.lictor_pid missing" }, 400);
328	    }
329	    const killResult = stopSessionByLictorPid(meta.lictor_pid);
330	    if (!killResult.ok) return c.json({ error: killResult.error }, 500);
331	    const now = Math.floor(Date.now() / 1000);
332	    deps.repo.setStatus(id, "ended", now, now);
333	    deps.repo.appendEvent({
334	      session_id: id,
335	      ts: now,
336	      kind: "end",
337	      payload: { stopped_by: "admin", duration_sec: now - session.started_at },
338	    });
339	    const ended = deps.repo.findSession(id)!;
340	    const flow = await runSessionEndFlow(
341	      {
342	        repo: deps.repo,
343	        chat: deps.chat,
344	        dispatcher: deps.dispatcher,
345	        personas: deps.personas,
346	        config: deps.config,
347	      },
348	      ended,
349	    );
350	    return c.json({
351	      ok: true,
352	      pid: meta.lictor_pid,
353	      report_generated: flow.report !== null,
354	      monologue_posted: flow.postedMessageId !== null,
355	    });
356	  });
357	
358	  // ── 管理 API: 3 つの runtime toggle ─────────────────────────────────
359	  // schema_meta 永続化 + AdminState 経由で dispatcher / rule engine / proposer
360	  // が次の tick から反映する. 再起動不要. Web UI (/rules ページ) からも操作可.
361	
362	  app.get("/v1/admin/chat-mute", (c) => {
