539	  // 管理 API: 新コード反映用の self-restart.
540	  // 子プロセスとして `npm run dev:backend` を detach spawn → 自分は 300ms 後に process.exit(0).
541	  // listen socket は exit で OS が回収. 数 100ms の downtime あり (in-flight request は drop).
542	  // loopback (127.0.0.1) でしか上がってない前提で、 追加認証は付けない.
543	  // test 時は CONCORDIA_RESTART_DRY_RUN=1 で spawn/exit を skip.
544	  app.post("/v1/admin/restart", (c) => {
545	    if (process.env.CONCORDIA_RESTART_DRY_RUN === "1") {
546	      return c.json({ ok: true, dry_run: true });
547	    }
548	    setTimeout(() => {
549	      // shell:true を避けてアタック面を減らす (CWE-78)。 固定コマンドだが OS shell を
550	      // 介さず、 Windows では npm.cmd を明示して直接 spawn する。
551	      const npmCmd = process.platform === "win32" ? "npm.cmd" : "npm";
552	      const child = spawn(npmCmd, ["run", "dev:backend"], {
553	        cwd: process.cwd(),
554	        detached: true,
555	        stdio: "ignore",
556	      });
557	      child.unref();
558	      setTimeout(() => process.exit(0), 200);
559	    }, 100);
560	    return c.json({ ok: true, message: "restarting (child spawning, parent will exit in ~300ms)" });
561	  });
562	
563	  app.post("/v1/admin/discord/start", async (c) => {
564	    if (!deps.discordAdmin) return c.json({ ok: false, error: "discord_admin_not_ready" }, 503);
565	    const r = await deps.discordAdmin.start();
566	    return c.json(r, r.ok ? 200 : 500);
567	  });
568	
569	  app.post("/v1/admin/discord/stop", async (c) => {
570	    if (!deps.discordAdmin) return c.json({ ok: false, error: "discord_admin_not_ready" }, 503);
571	    const r = await deps.discordAdmin.stop();
572	    return c.json(r, r.ok ? 200 : 500);
573	  });
574	
575	  app.post("/v1/admin/discord/restart", async (c) => {
576	    if (!deps.discordAdmin) return c.json({ ok: false, error: "discord_admin_not_ready" }, 503);
577	    const r = await deps.discordAdmin.restart();
578	    return c.json(r, r.ok ? 200 : 500);
579	  });
580	
581	  // Discord 接続設定をサービス内 (Web UI / API) から設定する (Slack /config と対の構成)。
582	  //  - GET  /config : redact 済み設定状態 (token 値は返さない)
583	  //  - PUT  /config : 設定更新 (token は暗号化保存) → bot を hot 再接続
584	  if (deps.discordConfig && deps.secretBox && deps.discordAdmin) {
585	    const discordConfig = deps.discordConfig;
586	    const secretBox = deps.secretBox;
587	    const discordAdmin = deps.discordAdmin;
588	    const DiscordPutSchema = z.object({
589	      enabled: z.boolean().optional(),
590	      // null / 空文字 = クリア (env フォールバックに戻す)、 文字列 = 設定
591	      guild_id: z.string().max(64).nullable().optional(),
592	      application_id: z.string().max(64).nullable().optional(),
593	      token: z.string().max(256).nullable().optional(),
594	    });
595	
596	    app.get("/v1/admin/discord/config", (c) =>
597	      c.json(discordConfigStatus(discordConfig, secretBox)),
598	    );
599	
600	    app.put("/v1/admin/discord/config", async (c) => {
601	      const body = await c.req.json().catch(() => null);
602	      const parsed = DiscordPutSchema.safeParse(body);
603	      if (!parsed.success) return c.json({ error: parsed.error.message }, 400);
604	      setDiscordConfig(discordConfig, secretBox, {
605	        enabled: parsed.data.enabled,
606	        guildId: parsed.data.guild_id,
607	        applicationId: parsed.data.application_id,
608	        token: parsed.data.token,
609	      });
610	      const restart = await discordAdmin.restart();
611	      return c.json({
612	        ok: restart.ok,
613	        status: discordConfigStatus(discordConfig, secretBox),
614	        restart,
615	      });
616	    });
617	  }
618	
619	  // Slack をサービス内から設定 (config GET/PUT + start/stop/restart)。3 点セットが揃った時のみ有効。
620	  if (deps.slackConfig && deps.secretBox && deps.slackAdmin) {
621	    app.route(
622	      "/v1/admin/slack",
623	      slackAdminRouter({ config: deps.slackConfig, secretBox: deps.secretBox, admin: deps.slackAdmin }),
624	    );
625	  }
626	
627	  return app;
628	}
629	
630	function isPlainObject(x: unknown): x is Record<string, unknown> {
631	  return !!x && typeof x === "object" && !Array.isArray(x);
632	}
