308	  useEffect(() => { void refresh(); }, []);
309	
310	  async function refresh() {
311	    try {
312	      const [s, m] = await Promise.all([
313	        fetch("/v1/admin/reaction-workflow").then((r) => r.json()),
314	        fetch("/v1/admin/reaction-mappings").then((r) => r.json()),
