391	        <p className="text-xs text-subtle mt-1">
392	          いずれも「投稿内容を変換して claude に渡す」。 既定の絵文字でトリガーされる。
393	        </p>
394	        <ul className="mt-2 space-y-2">
395	          {maps?.actions.map((a) => {
396	            const h = maps.action_help?.[a];
397	            const emojis = defaultEmojisByAction[a] ?? [];
398	            return (
399	              <li key={a} className="bg-surface border border-border rounded px-2 py-1.5">
400	                <div className="flex items-center gap-2 flex-wrap">
401	                  <span className="text-base">{emojis.join(" ") || "—"}</span>
402	                  <span className="font-mono text-xs text-accent">{a}</span>
403	                  {h?.label && <span className="text-xs font-medium">{h.label}</span>}
404	                </div>
405	                {h?.summary && <div className="text-xs text-subtle mt-0.5">{h.summary}</div>}
406	                {h?.mode && <div className="text-[11px] text-subtle mt-0.5">実行: {h.mode}</div>}
407	              </li>
408	            );
409	          })}
410	        </ul>
411	      </details>
412	
413	      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
414	        <div>
415	          <div className="text-sm font-medium">絵文字 → アクション マッピング</div>
416	          <div className="text-xs text-subtle mt-0.5">
417	            デフォルトは組み込み構成。 同じ絵文字に上書き登録すると custom が優先される。
418	          </div>
419	        </div>
420	
421	        <div className="flex items-center gap-2 flex-wrap">
422	          <input
423	            type="text" value={newEmoji} onChange={(e) => setNewEmoji(e.target.value)}
424	            placeholder="絵文字 (例 🔥)" disabled={busy === "add"}
425	            className="bg-muted border border-border rounded px-2 py-1 text-sm w-28"
426	          />
427	          <select
428	            value={newAction} onChange={(e) => setNewAction(e.target.value)} disabled={busy === "add"}
429	            className="bg-muted border border-border rounded px-2 py-1 text-sm"
430	          >
431	            {maps?.actions.map((a) => (
432	              <option key={a} value={a}>{maps.action_help?.[a]?.label ? `${a} — ${maps.action_help[a].label}` : a}</option>
433	            ))}
434	          </select>
435	          <button
436	            disabled={busy === "add" || !newEmoji.trim() || !newAction}
437	            onClick={() => void addMapping()}
438	            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
439	          >追加 / 上書き</button>
440	        </div>
441	
442	        <ul className="space-y-1">
443	          {effective.map((m) => (
444	            <li key={m.emoji} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
445	              <span className="text-lg w-7 text-center">{m.emoji}</span>
446	              <span className="text-subtle">→</span>
447	              <span className="font-mono text-xs" title={maps?.action_help?.[m.action]?.summary}>
448	                {m.action}{maps?.action_help?.[m.action]?.label ? ` (${maps.action_help[m.action].label})` : ""}
449	              </span>
450	              <span className={`ml-2 px-1.5 py-0.5 rounded text-[10px] border ${m.source === "custom" ? "bg-accent/20 border-accent text-accent" : "bg-muted border-border text-subtle"}`}>
451	                {m.source === "custom" ? "custom" : "default"}
452	              </span>
453	              {m.source === "custom" && (
454	                <button
455	                  disabled={busy === `rm:${m.emoji}`}
456	                  onClick={() => void removeOverride(m.emoji)}
457	                  className="ml-auto text-subtle hover:text-danger text-xs"
458	                >削除</button>
459	              )}
460	            </li>
461	          ))}
462	        </ul>
463	      </div>
