523	export function CostBudgetSection() {
524	  const [budget, setBudget] = useState<number | null>(null);
525	  const [today, setToday] = useState<number>(0);
526	  const [blocked, setBlocked] = useState<boolean>(false);
527	  const [draft, setDraft] = useState("");
528	  const [busy, setBusy] = useState(false);
529	  const [error, setError] = useState<string | null>(null);
530	
531	  useEffect(() => { void refresh(); }, []);
532	  useEffect(() => {
533	    // 当日消費は変化するので定期的に再取得 (30s)。
534	    const t = setInterval(() => { void refresh(); }, 30_000);
535	    return () => clearInterval(t);
536	  }, []);
537	
538	  async function refresh() {
539	    try {
540	      const s = (await fetch("/v1/admin/cost-budget").then((r) => r.json())) as {
541	        daily_token_budget: number; today_tokens: number; blocked: boolean;
542	      };
543	      setBudget(s.daily_token_budget);
544	      setToday(s.today_tokens);
545	      setBlocked(s.blocked);
546	      setDraft(String(s.daily_token_budget));
547	      setError(null);
548	    } catch (err) { setError((err as Error).message); }
549	  }
550	
551	  async function apply() {
552	    const n = Number(draft);
553	    if (!Number.isFinite(n) || n < 0) { setError("0 以上の数値を入力"); return; }
554	    setBusy(true); setError(null);
555	    try {
556	      await putJson("/v1/admin/cost-budget", { daily_token_budget: Math.floor(n) });
557	      await refresh();
558	    } catch (err) { setError((err as Error).message); } finally { setBusy(false); }
559	  }
560	
561	  const pct = budget && budget > 0 ? Math.min(100, Math.round((today / budget) * 100)) : 0;
562	
563	  return (
564	    <section className="space-y-3">
565	      <div>
566	        <h2 className="font-semibold text-sm">コスト予算 (日次トークン)</h2>
567	        <p className="text-subtle text-xs mt-0.5">
568	          当日 (ローカル日) のトークン消費合計が上限に達したら、 Concordia 発の命令
569	          (新規 spawn / dispatcher 発話 / リアクションWF / rule engine) を止める。
570	          外部バッチ・別ツール起動の Claude/Codex も合算対象。 0 = 無効。
571	        </p>
572	      </div>
573	
574	      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
575	        <div className="flex items-center gap-2 flex-wrap text-xs">
576	          <span className="text-subtle">当日消費:</span>
577	          <span className="font-mono">{today.toLocaleString()} tok</span>
578	          <span className="text-subtle">/ 予算:</span>
579	          <span className="font-mono">{budget === null ? "..." : budget === 0 ? "(無効)" : budget.toLocaleString()}</span>
580	          {blocked && (
581	            <span className="px-2 py-0.5 rounded text-xs border bg-danger/20 border-danger text-danger">
582	              ⛔ ブロック中
583	            </span>
584	          )}
585	        </div>
586	        {budget !== null && budget > 0 && (
587	          <div className="h-2 w-full rounded bg-muted overflow-hidden">
588	            <div
589	              className={`h-full ${blocked ? "bg-danger" : pct >= 80 ? "bg-warn" : "bg-ok"}`}
590	              style={{ width: `${pct}%` }}
591	            />
592	          </div>
593	        )}
594	        <div className="flex items-center gap-2 flex-wrap">
595	          <span className="text-xs text-subtle shrink-0">上限 (tok):</span>
596	          <input
597	            type="number"
598	            min={0}
599	            value={draft}
600	            onChange={(e) => setDraft(e.target.value)}
601	            disabled={busy}
602	            placeholder="0 = 無効 (例 2000000)"
603	            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[160px]"
604	          />
605	          <button
606	            disabled={busy || draft === String(budget ?? "")}
607	            onClick={() => void apply()}
608	            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
609	          >
610	            apply
611	          </button>
612	        </div>
613	      </div>
614	      {error && <div className="text-danger text-xs">{error}</div>}
615	    </section>
616	  );
617	}
