/**
 * セッション別 提案レートリミット — dispatcher の提案 (proposal) 発火ゲート.
 *
 * dispatcher が 1 session へ提案 task (chitchat-suggest / review-summary /
 * chat-reply / peer-log-react) を enqueue する前に通す. 「窓 (秒) 内に N 回まで」
 * を session ごとに評価し、 窓内で上限に達していれば今回の提案をスキップさせる.
 * 窓が明けたらカウントをリセットして再開する. 暴走 / 過剰提案の抑止が目的.
 *
 * 設定 (窓 + 上限) は AdminState (schema_meta 永続化) が持ち、 グローバル既定 +
 * session 個別上書きを resolveLimit 経由で解決する. カウンタ状態も schema_meta に
 * 永続化する (load / save を AdminState に委譲) ので、 再起動を跨いでも窓内カウントが
 * 引き継がれ、 restart で上限を回避できない.
 *
 * 既存の kill-switch (chat-mute / cost-budget) と同じ「dispatcher の deps に
 * 注入する live 評価ゲート」の作法に寄せている.
 */

/** 窓 (秒) と上限回数のペア. max_count<=0 または window_sec<=0 で無効 (常に許可). */
export interface ProposalRateLimit {
  window_sec: number;
  max_count: number;
}

/** session 単位の窓カウンタ状態 (schema_meta に JSON 永続化される). */
export interface ProposalRateCounter {
  /** 現在の窓の開始 epoch 秒. */
  window_start: number;
  /** 現在の窓で許可済の提案回数. */
  count: number;
}

export type ProposalRateCounters = Record<string, ProposalRateCounter>;

export interface RateDecision {
  allowed: boolean;
  /** allowed=false のときの理由 (ログ用). */
  reason?: string;
}

export interface ProposalRateLimiterDeps {
  /** 対象 session の実効 limit (global 既定 + session 上書き) を解決する. */
  resolveLimit: (sessionId: string) => ProposalRateLimit;
  /** カウンタ状態を schema_meta から読む. */
  load: () => ProposalRateCounters;
  /** カウンタ状態を schema_meta に書く. */
  save: (counters: ProposalRateCounters) => void;
  /** 現在時刻 (epoch 秒). テスト注入用. 既定はシステム時計. */
  now?: () => number;
}

/** 窓の最大長より十分大きい古いエントリは捨てて map を有界に保つ (秒). */
const COUNTER_PRUNE_AGE_SEC = 86_400;

/**
 * dispatcher が提案を出す前に通すゲート. tryDispatch が allowed=true を返したら
 * その session の窓カウントは既に +1 されている (永続化済). false なら未加算.
 */
export class ProposalRateLimiter {
  private readonly now: () => number;

  constructor(private readonly deps: ProposalRateLimiterDeps) {
    this.now = deps.now ?? (() => Math.floor(Date.now() / 1000));
  }

  /**
   * 提案を出してよいか判定する. 許可時はカウンタを +1 して永続化し true を返す.
   * 窓内で上限に達していれば false (理由付き) を返し、 カウンタは増やさない.
   */
  tryDispatch(sessionId: string): RateDecision {
    const limit = this.deps.resolveLimit(sessionId);
    // 無効化 (常に許可): 上限 0 以下 / 窓 0 以下.
    if (!(limit.max_count > 0) || !(limit.window_sec > 0)) return { allowed: true };

    const now = this.now();
    const counters = this.deps.load();
    let entry = counters[sessionId];
    // 未記録 or 窓が明けている → リセット (新しい窓を開始).
    if (!entry || now - entry.window_start >= limit.window_sec) {
      entry = { window_start: now, count: 0 };
    }

    if (entry.count >= limit.max_count) {
      // 窓内で上限到達 → 今回の提案はスキップ (カウントは据え置き).
      counters[sessionId] = entry;
      this.deps.save(prune(counters, now));
      return {
        allowed: false,
        reason: `proposal rate limit reached: ${entry.count}/${limit.max_count} within ${limit.window_sec}s window`,
      };
    }

    entry.count += 1;
    counters[sessionId] = entry;
    this.deps.save(prune(counters, now));
    return { allowed: true };
  }
}

/** 1 日以上前に開始した窓のエントリを捨てる (どんな実効窓でも確実に失効済). */
function prune(counters: ProposalRateCounters, now: number): ProposalRateCounters {
  for (const [sid, entry] of Object.entries(counters)) {
    if (now - entry.window_start > COUNTER_PRUNE_AGE_SEC) delete counters[sid];
  }
  return counters;
}

