      const parsed = JSON.parse(raw) as unknown;
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        return parsed as Record<string, string>;
      }
    } catch {
      // 壊れた値は無視 (空辞書扱い)。
    }
    return {};
  }

  /** 1 件 upsert (emoji→action)。 */
  setReactionEmojiOverride(emoji: string, action: string): void {
    const e = emoji.trim();
    if (!e) return;
    const cur = this.getReactionEmojiOverrides();
    cur[e] = action;
    this.setRaw(KEY_REACTION_MAPPINGS, JSON.stringify(cur));
  }

  /** 1 件削除 (既定写像に戻す)。 */
  deleteReactionEmojiOverride(emoji: string): void {
    const cur = this.getReactionEmojiOverrides();
    if (!Object.prototype.hasOwnProperty.call(cur, emoji.trim())) return;
    delete cur[emoji.trim()];
    this.setRaw(KEY_REACTION_MAPPINGS, JSON.stringify(cur));
  }

  // ── Lictor 起動設定 (spawn の launcher 解決に使う) ─────────────────────

  getLictorMode(): LictorMode {
    const raw = this.getRaw(KEY_LICTOR_MODE);
    return (LICTOR_MODES as string[]).includes(raw ?? "") ? (raw as LictorMode) : "auto";
  }

  setLictorMode(value: string): void {
    if (!(LICTOR_MODES as string[]).includes(value)) {
      throw new Error(`lictor_mode must be one of ${LICTOR_MODES.join(" / ")}`);
    }
    this.setRaw(KEY_LICTOR_MODE, value);
  }

  /** dev モードのローカル Lictor リポ。 未設定なら constructor 既定。 */
  getLictorDevPath(): string {
    const raw = this.getRaw(KEY_LICTOR_DEV_PATH);
    if (raw !== null && raw.trim() !== "") return raw;
    return this.defaults.lictorDevPath ?? "";
  }

  setLictorDevPath(value: string): void {
    this.setRaw(KEY_LICTOR_DEV_PATH, value.trim());
  }

  /** prod モードの同梱 Lictor exe のパス (Release 公開物)。 */
  getLictorProdExe(): string {
    return this.getRaw(KEY_LICTOR_PROD_EXE) ?? "";
  }

  setLictorProdExe(value: string): void {
    this.setRaw(KEY_LICTOR_PROD_EXE, value.trim());
  }

  // ── コスト予算 (日次トークン上限) ────────────────────────────────────
  // 0 = 無効 (ブロックしない)。 1 以上 = その日のトークン消費合計が上限に
  // 達したら Concordia 発の命令 (spawn / dispatcher / リアクションWF / proposer)
  // を止める。 外部バッチのトークンも CostUsageTracker 経由で計上される。

  /** 日次トークン予算 (0 = 無効)。 未設定なら 0。 */
  getDailyTokenBudget(): number {
    const raw = this.getRaw(KEY_DAILY_TOKEN_BUDGET);
    if (raw === null) return 0;
    const n = Number(raw);
    return Number.isFinite(n) && n > 0 ? Math.floor(n) : 0;
  }

  setDailyTokenBudget(value: number): void {
    if (!Number.isFinite(value)) {
      throw new Error("daily_token_budget must be a finite number");
    }
    this.setRaw(KEY_DAILY_TOKEN_BUDGET, String(Math.max(0, Math.floor(value))));
  }

  // ── セッション別 提案レートリミット ──────────────────────────────────
  // dispatcher が提案 (chitchat / review / chat-reply / peer-react) を 1 session に
  // enqueue する前のゲート設定. グローバル既定 (window_sec / max_count) + session
  // 個別上書き. カウンタ状態も schema_meta に永続化し、 ProposalRateLimiter が
  // load/save で読み書きする (再起動を跨いで窓内カウントを維持)。 max_count 0 で無効。

  /** グローバル既定の窓 + 上限 (未設定なら 60 秒 / 5 回)。 */
  getProposalRateLimit(): ProposalRateLimit {
    const raw = this.getRaw(KEY_PROPOSAL_RATE_LIMIT);
    const fallback: ProposalRateLimit = {
      window_sec: DEFAULT_PROPOSAL_RATE_WINDOW_SEC,
      max_count: DEFAULT_PROPOSAL_RATE_MAX_COUNT,
    };
    if (raw === null) return fallback;
    return sanitizeRateLimit(parseJsonObject(raw), fallback);
  }

  /** グローバル既定を設定 (clamp 済で永続化)。 非有限値は throw。 */
  setProposalRateLimit(value: ProposalRateLimit): void {
    this.setRaw(KEY_PROPOSAL_RATE_LIMIT, JSON.stringify(assertRateLimit(value)));
  }

  /** session→limit の上書き辞書 (空なら {})。 */
  getProposalRateLimitOverrides(): Record<string, ProposalRateLimit> {
    const raw = this.getRaw(KEY_PROPOSAL_RATE_OVERRIDES);
    if (!raw) return {};
    const obj = parseJsonObject(raw);
    const out: Record<string, ProposalRateLimit> = {};
    const fallback = this.getProposalRateLimit();
    for (const [sid, v] of Object.entries(obj)) {
      if (sid.trim()) out[sid] = sanitizeRateLimit(v, fallback);
    }
    return out;
  }

  /** 1 session の上書きを upsert (clamp 済)。 非有限値は throw。 */
  setProposalRateLimitOverride(sessionId: string, value: ProposalRateLimit): void {
    const sid = sessionId.trim();
    if (!sid) throw new Error("session_id required");
    const cur = this.getProposalRateLimitOverrides();
    cur[sid] = assertRateLimit(value);
    this.setRaw(KEY_PROPOSAL_RATE_OVERRIDES, JSON.stringify(cur));
  }

  /** 1 session の上書きを削除 (グローバル既定に戻す)。 */
  deleteProposalRateLimitOverride(sessionId: string): void {
    const cur = this.getProposalRateLimitOverrides();
    if (!Object.prototype.hasOwnProperty.call(cur, sessionId.trim())) return;
    delete cur[sessionId.trim()];
    this.setRaw(KEY_PROPOSAL_RATE_OVERRIDES, JSON.stringify(cur));
  }

  /** 実効 limit: session 上書きがあればそれ、 無ければグローバル既定。 */
  getEffectiveProposalRateLimit(sessionId: string): ProposalRateLimit {
    return this.getProposalRateLimitOverrides()[sessionId] ?? this.getProposalRateLimit();
  }

  /** カウンタ状態を読む (壊れた値は {})。 ProposalRateLimiter.load 用。 */
  getProposalRateCounters(): ProposalRateCounters {
    const raw = this.getRaw(KEY_PROPOSAL_RATE_COUNTERS);
    if (!raw) return {};
    const obj = parseJsonObject(raw);
    const out: ProposalRateCounters = {};
    for (const [sid, v] of Object.entries(obj)) {
      if (v && typeof v === "object") {
        const ws = Number((v as Record<string, unknown>).window_start);
        const c = Number((v as Record<string, unknown>).count);
        if (Number.isFinite(ws) && Number.isFinite(c)) {
          out[sid] = { window_start: Math.floor(ws), count: Math.floor(c) };
        }
      }
    }
    return out;
  }

  /** カウンタ状態を書く。 ProposalRateLimiter.save 用。 */
  setProposalRateCounters(counters: ProposalRateCounters): void {
    this.setRaw(KEY_PROPOSAL_RATE_COUNTERS, JSON.stringify(counters));
  }

  snapshot(): {
    chat_muted: boolean;
    rules_enabled: boolean;
    rule_proposer_interval_sec: number;
    workspace_root: string;
    workspace_roots: string[];
    github_org: string;
    reaction_workflow_enabled: boolean;
    lictor_mode: LictorMode;
    lictor_dev_path: string;
    lictor_prod_exe: string;
    daily_token_budget: number;
    proposal_rate_limit: ProposalRateLimit;
    proposal_rate_overrides: Record<string, ProposalRateLimit>;
  } {
    return {
      chat_muted: this.getChatMuted(),
      rules_enabled: this.getRulesEnabled(),
      rule_proposer_interval_sec: this.getRuleProposerIntervalSec(),
      workspace_root: this.getWorkspaceRoot(),
      workspace_roots: this.getWorkspaceRoots(),
      github_org: this.getGithubOrg(),
      reaction_workflow_enabled: this.getReactionWorkflowEnabled(),
      lictor_mode: this.getLictorMode(),
      lictor_dev_path: this.getLictorDevPath(),
      lictor_prod_exe: this.getLictorProdExe(),
      daily_token_budget: this.getDailyTokenBudget(),
      proposal_rate_limit: this.getProposalRateLimit(),
      proposal_rate_overrides: this.getProposalRateLimitOverrides(),
    };
  }

  // ── internals ───────────────────────────────────────────────────────

  private getRaw(key: string): string | null {
    const row = this.db.prepare(`SELECT value FROM schema_meta WHERE key = ?`).get(key) as
      | { value: string }
      | undefined;
    return row?.value ?? null;
  }

  private setRaw(key: string, value: string): void {
    this.db
      .prepare(`INSERT OR REPLACE INTO schema_meta(key, value) VALUES (?, ?)`)
      .run(key, value);
  }

  private getBool(key: string, fallback: boolean): boolean {
    const raw = this.getRaw(key);
    if (raw === null) return fallback;
    return raw === "1" || raw === "true";
  }

  private setBool(key: string, value: boolean): void {
    this.setRaw(key, value ? "1" : "0");
  }
}

function clamp(n: number, lo: number, hi: number): number {
  return Math.max(lo, Math.min(hi, n));
}

/** schema_meta に入った JSON 配列文字列を string[] に復元 (壊れた値は [])。 */
function parseRootsJson(raw: string): string[] {
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (Array.isArray(parsed)) return parsed.filter((v): v is string => typeof v === "string");
  } catch {
    // 壊れた値は無視。
  }
  return [];
}

/** trim + 空除去 + 正規化パスで重複除去 (先頭優先) (pure)。 */
function cleanRoots(roots: readonly string[]): string[] {
  const seen = new Set<string>();
  const out: string[] = [];
  for (const r of roots) {
    const t = r.trim();
    if (!t) continue;
    const key = t.replace(/\\/g, "/").replace(/\/+$/, "").toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(t);
  }
  return out;
}

export const ADMIN_PROPOSER_INTERVAL_MIN = PROPOSER_INTERVAL_MIN;
export const ADMIN_PROPOSER_INTERVAL_MAX = PROPOSER_INTERVAL_MAX;

