// ─── セッション別 提案レートリミット (窓 + 上限、 グローバル既定 + session 上書き) ──

interface RateLimit { window_sec: number; max_count: number }
interface ProposalRateState {
  default: RateLimit;
  overrides: Record<string, RateLimit>;
  limits: { window_min_sec: number; window_max_sec: number; count_min: number; count_max: number };
}

export function ProposalRateLimitSection() {
  const [state, setState] = useState<ProposalRateState | null>(null);
  const [winDraft, setWinDraft] = useState("");
  const [cntDraft, setCntDraft] = useState("");
  const [ovSession, setOvSession] = useState("");
  const [ovWin, setOvWin] = useState("");
  const [ovCnt, setOvCnt] = useState("");
  const [busy, setBusy] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => { void refresh(); }, []);

  async function refresh() {
    try {
      const s = (await fetch("/v1/admin/proposal-rate-limit").then((r) => r.json())) as ProposalRateState;
      setState(s);
      setWinDraft(String(s.default.window_sec));
      setCntDraft(String(s.default.max_count));
      setError(null);
    } catch (err) { setError((err as Error).message); }
  }

  async function applyDefault() {
    const window_sec = Number(winDraft);
    const max_count = Number(cntDraft);
    if (!Number.isFinite(window_sec) || !Number.isFinite(max_count)) { setError("数値を入力"); return; }
    setBusy("default"); setError(null);
    try { await putJson("/v1/admin/proposal-rate-limit", { window_sec, max_count }); await refresh(); }
    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function addOverride() {
    const session_id = ovSession.trim();
    const window_sec = Number(ovWin);
    const max_count = Number(ovCnt);
    if (!session_id || !Number.isFinite(window_sec) || !Number.isFinite(max_count)) {
      setError("session_id と窓 / 上限 (数値) を入力"); return;
    }
    setBusy("ov-add"); setError(null);
    try {
      await putJson("/v1/admin/proposal-rate-limit/override", { session_id, window_sec, max_count });
      setOvSession(""); setOvWin(""); setOvCnt("");
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function removeOverride(sessionId: string) {
    setBusy(`ov-rm:${sessionId}`); setError(null);
    try {
      const r = await fetch(`/v1/admin/proposal-rate-limit/override/${encodeURIComponent(sessionId)}`, { method: "DELETE" });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  const overrides = state ? Object.entries(state.overrides) : [];

  return (
    <section className="space-y-3">
      <div>
        <h2 className="font-semibold text-sm">提案レートリミット (セッション別)</h2>
        <p className="text-subtle text-xs mt-0.5">
          dispatcher が 1 session へ提案 (chitchat / 軽レビュー / chat-reply / peer-react) を出す前のゲート。
          「窓 (秒) 内に最大 N 回」を超えたら今回の提案をスキップ (窓明けで再開)。 暴走・過剰提案の抑止用。
          上限 0 = 無効 (制限なし)。 設定・カウンタ状態は schema_meta 永続化、 即時反映。
        </p>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
        <div className="text-sm font-medium">グローバル既定</div>
        <div className="text-xs text-subtle">
          現在: {state ? `${state.default.window_sec}s 窓 / ${state.default.max_count} 回` : "..."}
          {state && ` (窓 [${state.limits.window_min_sec}, ${state.limits.window_max_sec}] / 回数 [${state.limits.count_min}, ${state.limits.count_max}])`}
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <label className="text-xs text-subtle">窓 (秒)</label>
          <input
            type="number" min={state?.limits.window_min_sec ?? 1} max={state?.limits.window_max_sec ?? 86400}
            value={winDraft} onChange={(e) => setWinDraft(e.target.value)} disabled={busy === "default"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <label className="text-xs text-subtle">上限 (回)</label>
          <input
            type="number" min={state?.limits.count_min ?? 0} max={state?.limits.count_max ?? 100000}
            value={cntDraft} onChange={(e) => setCntDraft(e.target.value)} disabled={busy === "default"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <button
            disabled={busy === "default" || (winDraft === String(state?.default.window_sec ?? "") && cntDraft === String(state?.default.max_count ?? ""))}
            onClick={() => void applyDefault()}
            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >apply</button>
        </div>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
        <div>
          <div className="text-sm font-medium">session 個別上書き</div>
          <div className="text-xs text-subtle mt-0.5">特定 session だけ別の窓 / 上限にする。 無ければグローバル既定が適用される。</div>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <input
            type="text" value={ovSession} onChange={(e) => setOvSession(e.target.value)}
            placeholder="session_id" disabled={busy === "ov-add"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[160px]"
          />
          <input
            type="number" value={ovWin} onChange={(e) => setOvWin(e.target.value)}
            placeholder="窓秒" disabled={busy === "ov-add"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
          />
          <input
            type="number" value={ovCnt} onChange={(e) => setOvCnt(e.target.value)}
            placeholder="上限" disabled={busy === "ov-add"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
          />
          <button
            disabled={busy === "ov-add" || !ovSession.trim()}
            onClick={() => void addOverride()}
            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >追加 / 上書き</button>
        </div>
        <ul className="space-y-1">
          {overrides.length === 0 && <li className="text-xs text-subtle">(上書きなし)</li>}
          {overrides.map(([sid, lim]) => (
            <li key={sid} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
              <span className="font-mono text-xs truncate">{sid}</span>
              <span className="text-subtle">→</span>
              <span className="font-mono text-xs">{lim.window_sec}s / {lim.max_count} 回</span>
              <button
                disabled={busy === `ov-rm:${sid}`}
                onClick={() => void removeOverride(sid)}
                className="ml-auto text-subtle hover:text-danger text-xs"
              >削除</button>
            </li>
          ))}
        </ul>
      </div>

      {error && <div className="text-danger text-xs">{error}</div>}
    </section>
  );
}

