describe("proposal rate limit", () => {
  it("既定は 60 秒 / 5 回", () => {
    expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 60, max_count: 5 });
  });

  it("グローバル既定の set-get + clamp + 永続", () => {
    env.state.setProposalRateLimit({ window_sec: 30, max_count: 3 });
    expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 30, max_count: 3 });
    expect(new AdminState(env.db).getProposalRateLimit()).toEqual({ window_sec: 30, max_count: 3 });
    // clamp: 窓は最小 1 / 最大 86400、 上限は最小 0。
    env.state.setProposalRateLimit({ window_sec: 0, max_count: -5 });
    expect(env.state.getProposalRateLimit()).toEqual({ window_sec: 1, max_count: 0 });
  });

  it("非有限値は throw", () => {
    expect(() => env.state.setProposalRateLimit({ window_sec: NaN, max_count: 5 })).toThrow();
    expect(() => env.state.setProposalRateLimit({ window_sec: 60, max_count: Infinity })).toThrow();
  });

  it("session 個別上書き upsert / delete / effective 解決", () => {
    env.state.setProposalRateLimit({ window_sec: 60, max_count: 5 });
    expect(env.state.getEffectiveProposalRateLimit("s1")).toEqual({ window_sec: 60, max_count: 5 });
    env.state.setProposalRateLimitOverride("s1", { window_sec: 10, max_count: 2 });
    expect(env.state.getEffectiveProposalRateLimit("s1")).toEqual({ window_sec: 10, max_count: 2 });
    // 他 session はグローバル既定のまま。
    expect(env.state.getEffectiveProposalRateLimit("s2")).toEqual({ window_sec: 60, max_count: 5 });
    // 永続。
    expect(new AdminState(env.db).getProposalRateLimitOverrides()).toEqual({ s1: { window_sec: 10, max_count: 2 } });
    env.state.deleteProposalRateLimitOverride("s1");
    expect(env.state.getEffectiveProposalRateLimit("s1")).toEqual({ window_sec: 60, max_count: 5 });
  });

  it("カウンタ状態の round-trip + 永続", () => {
    env.state.setProposalRateCounters({ s1: { window_start: 1000, count: 3 } });
    expect(new AdminState(env.db).getProposalRateCounters()).toEqual({ s1: { window_start: 1000, count: 3 } });
  });
});

