import { AdminState } from "../src/admin/state.js";
import {
  ProposalRateLimiter,
  type ProposalRateLimit,
  type ProposalRateCounters,
} from "../src/dispatcher-rate-limit.js";

/** AdminState 永続化バックエンドで限界器を組む (本番と同じ配線)。 now は注入で進める。 */
function bootWithAdminState(limit: ProposalRateLimit, now: { t: number }) {
  const db = makeTestDb();
  const state = new AdminState(db);
  state.setProposalRateLimit(limit);
  const limiter = new ProposalRateLimiter({
    resolveLimit: (sid) => state.getEffectiveProposalRateLimit(sid),
    load: () => state.getProposalRateCounters(),
    save: (c) => state.setProposalRateCounters(c),
    now: () => now.t,
  });
  return { db, state, limiter };
}

describe("ProposalRateLimiter", () => {
  let now: { t: number };
  beforeEach(() => { now = { t: 1000 }; });

  it("窓内で上限に達すると以降の提案をスキップする", () => {
    const { limiter } = bootWithAdminState({ window_sec: 60, max_count: 2 }, now);
    expect(limiter.tryDispatch("s1").allowed).toBe(true);  // 1/2
    expect(limiter.tryDispatch("s1").allowed).toBe(true);  // 2/2
    const denied = limiter.tryDispatch("s1");               // 3 回目 → skip
    expect(denied.allowed).toBe(false);
    expect(denied.reason).toMatch(/rate limit/);
  });

  it("窓が明けたらカウントをリセットして再開する", () => {
    const { limiter } = bootWithAdminState({ window_sec: 60, max_count: 2 }, now);
    expect(limiter.tryDispatch("s1").allowed).toBe(true);
    expect(limiter.tryDispatch("s1").allowed).toBe(true);
    expect(limiter.tryDispatch("s1").allowed).toBe(false); // 窓内で上限
    now.t += 60;                                            // 窓明け
    expect(limiter.tryDispatch("s1").allowed).toBe(true);  // 再開
    expect(limiter.tryDispatch("s1").allowed).toBe(true);
    expect(limiter.tryDispatch("s1").allowed).toBe(false);
  });

  it("session ごとに独立してカウントする", () => {
    const { limiter } = bootWithAdminState({ window_sec: 60, max_count: 1 }, now);
    expect(limiter.tryDispatch("a").allowed).toBe(true);
    expect(limiter.tryDispatch("a").allowed).toBe(false); // a は上限
    expect(limiter.tryDispatch("b").allowed).toBe(true);  // b は別カウント
  });

  it("session 上書きがグローバル既定より優先される", () => {
    const { state, limiter } = bootWithAdminState({ window_sec: 60, max_count: 5 }, now);
    state.setProposalRateLimitOverride("strict", { window_sec: 60, max_count: 1 });
    expect(limiter.tryDispatch("strict").allowed).toBe(true);
    expect(limiter.tryDispatch("strict").allowed).toBe(false); // 上書き 1 回で上限
    // グローバル既定の session は 5 回まで通る。
    for (let i = 0; i < 5; i++) expect(limiter.tryDispatch("loose").allowed).toBe(true);
    expect(limiter.tryDispatch("loose").allowed).toBe(false);
  });

  it("max_count 0 は無効化 (常に許可)", () => {
    const { limiter } = bootWithAdminState({ window_sec: 60, max_count: 0 }, now);
    for (let i = 0; i < 100; i++) expect(limiter.tryDispatch("s1").allowed).toBe(true);
  });

  it("カウンタ状態が永続化され、 再起動 (新インスタンス) を跨いで窓内カウントを維持する", () => {
    const { db, limiter } = bootWithAdminState({ window_sec: 60, max_count: 2 }, now);
    expect(limiter.tryDispatch("s1").allowed).toBe(true);
    expect(limiter.tryDispatch("s1").allowed).toBe(true);
    // 再起動相当: 同 DB から AdminState + limiter を組み直す。
    const state2 = new AdminState(db);
    const counters: ProposalRateCounters = state2.getProposalRateCounters();
    expect(counters.s1.count).toBe(2);
    const limiter2 = new ProposalRateLimiter({
      resolveLimit: (sid) => state2.getEffectiveProposalRateLimit(sid),
      load: () => state2.getProposalRateCounters(),
      save: (c) => state2.setProposalRateCounters(c),
      now: () => now.t,
    });
    // restart 直後でも窓内なので上限到達済 → skip (restart で回避できない)。
    expect(limiter2.tryDispatch("s1").allowed).toBe(false);
  });
});

