describe("Dispatcher — セッション別 提案レートリミット", () => {
  let env: ReturnType<typeof fresh>;
  beforeEach(() => { env = fresh(); });

  /** AdminState 永続化バックエンドの限界器を now 注入で組む。 */
  function limiter(env: ReturnType<typeof fresh>, now: { t: number }) {
    const state = new AdminState(env.db);
    state.setProposalRateLimit({ window_sec: 60, max_count: 1 }); // 窓 60s / 1 回
    return new ProposalRateLimiter({
      resolveLimit: (sid) => state.getEffectiveProposalRateLimit(sid),
      load: () => state.getProposalRateCounters(),
      save: (c) => state.setProposalRateCounters(c),
      now: () => now.t,
    });
  }

  it("上限到達後の提案 (chat-reply) はスキップされ、 窓明けで再開する", () => {
    startSession(env.sessions, "a");
    startSession(env.sessions, "b");
    const now = { t: 1000 };
    const d = new Dispatcher({ ...env, rng: () => 0.05, now: DAYTIME, proposalRateLimiter: limiter(env, now) });

    // 1 回目: b に chat-reply が enqueue される (1/1)。
    d.onChatPosted({ id: 1, channel: "chitchat", session_id: "a", text: "一言目", author_label: "魂", is_actionable: false });
    expect(env.tasks.pull("b").filter((t) => t.kind === "chat-reply").length).toBe(1);

    // 2 回目 (同窓内): b は上限到達 → スキップ。
    d.onChatPosted({ id: 2, channel: "chitchat", session_id: "a", text: "二言目", author_label: "魂", is_actionable: false });
    expect(env.tasks.pull("b").filter((t) => t.kind === "chat-reply").length).toBe(0);

    // 窓明け → 再開。
    now.t += 60;
    d.onChatPosted({ id: 3, channel: "chitchat", session_id: "a", text: "三言目", author_label: "魂", is_actionable: false });
    expect(env.tasks.pull("b").filter((t) => t.kind === "chat-reply").length).toBe(1);
  });

  it("ライフサイクル通知 (session-departed) はレート制限の対象外", () => {
    startSession(env.sessions, "lost");
    startSession(env.sessions, "peer");
    env.sessions.setStatus("lost", "lost", 100);
