it("proposal-rate-limit: GET 既定 + PUT global + override upsert/delete", async () => {
  const get = await env.app.request("/v1/admin/proposal-rate-limit");
  expect(get.status).toBe(200);
  const body = (await get.json()) as {
    default: { window_sec: number; max_count: number };
    overrides: Record<string, { window_sec: number; max_count: number }>;
    limits: { window_min_sec: number; count_min: number };
  };
  expect(body.default).toEqual({ window_sec: 60, max_count: 5 });
  expect(body.overrides).toEqual({});
  expect(typeof body.limits.window_min_sec).toBe("number");

  // グローバル既定の更新 (clamp 込み)。
  const put = await env.app.request("/v1/admin/proposal-rate-limit", {
    method: "PUT",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ window_sec: 30, max_count: 3 }),
  });
  expect(put.status).toBe(200);
  expect((await put.json() as { default: unknown }).default).toEqual({ window_sec: 30, max_count: 3 });

  // session 上書きの upsert。
  const ov = await env.app.request("/v1/admin/proposal-rate-limit/override", {
    method: "PUT",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ session_id: "s1", window_sec: 10, max_count: 1 }),
  });
  expect(ov.status).toBe(200);
  expect(env.adminState.getEffectiveProposalRateLimit("s1")).toEqual({ window_sec: 10, max_count: 1 });

  // /v1/admin/state にも反映される。
  const state = await env.app.request("/v1/admin/state");
  const sj = (await state.json()) as { proposal_rate_limit: unknown; proposal_rate_overrides: unknown };
  expect(sj.proposal_rate_limit).toEqual({ window_sec: 30, max_count: 3 });
  expect(sj.proposal_rate_overrides).toEqual({ s1: { window_sec: 10, max_count: 1 } });

  // delete override。
  const del = await env.app.request("/v1/admin/proposal-rate-limit/override/s1", { method: "DELETE" });
  expect(del.status).toBe(200);
  expect(env.adminState.getProposalRateLimitOverrides()).toEqual({});
});

